"""Tests for `cortex.ai.util.validation` (port of validation.test.ts)."""

from __future__ import annotations

from typing import Any

import pytest

from cortex.ai.types import Tool, ToolCall
from cortex.ai.util.validation import validate_tool_arguments


def _create_tool_call_with_plain_schema(
    schema: dict[str, Any],
    value: Any,
) -> tuple[Tool, ToolCall]:
    """Create a Tool and ToolCall pair with a plain JSON schema wrapping the given value."""
    tool = Tool(
        name="echo",
        description="Echo tool",
        parameters={
            "type": "object",
            "properties": {
                "value": schema,
            },
            "required": ["value"],
        },
    )

    tool_call = ToolCall(
        type="toolCall",
        id="tool-1",
        name="echo",
        arguments={"value": value},
    )

    return tool, tool_call


def test_validates_with_typebox_schema() -> None:
    """Validates arguments against a TypeBox-style schema (dict in Python)."""
    tool = Tool(
        name="echo",
        description="Echo tool",
        parameters={
            "type": "object",
            "properties": {
                "count": {"type": "number"},
            },
        },
    )
    tool_call = ToolCall(
        type="toolCall",
        id="tool-1",
        name="echo",
        arguments={"count": "42"},
    )

    result = validate_tool_arguments(tool, tool_call)
    assert result == {"count": 42}


def test_coerces_plain_json_schema_with_number_string() -> None:
    """Coerces string to number when schema type is number."""
    schema = {"type": "number"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "42")
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": 42}


def test_coerces_plain_json_schema_with_boolean_true() -> None:
    """Coerces string 'true' to boolean true when schema type is boolean."""
    schema = {"type": "boolean"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "true")
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": True}


def test_coerces_plain_json_schema_with_boolean_false() -> None:
    """Coerces string 'false' to boolean false when schema type is boolean."""
    schema = {"type": "boolean"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "false")
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": False}


def test_coerces_plain_json_schema_with_boolean_one() -> None:
    """Coerces number 1 to boolean true when schema type is boolean."""
    schema = {"type": "boolean"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, 1)
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": True}


def test_coerces_plain_json_schema_with_boolean_zero() -> None:
    """Coerces number 0 to boolean false when schema type is boolean."""
    schema = {"type": "boolean"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, 0)
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": False}


def test_coerces_plain_json_schema_with_null_to_string() -> None:
    """Coerces null to empty string when schema type is string."""
    schema = {"type": "string"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, None)
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": ""}


def test_coerces_plain_json_schema_with_boolean_to_string() -> None:
    """Coerces boolean true to string 'true' when schema type is string."""
    schema = {"type": "string"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, True)
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": "true"}


def test_coerces_plain_json_schema_with_empty_string_to_null() -> None:
    """Coerces empty string to null when schema type is null."""
    schema = {"type": "null"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "")
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": None}


def test_coerces_plain_json_schema_with_zero_to_null() -> None:
    """Coerces 0 to null when schema type is null."""
    schema = {"type": "null"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, 0)
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": None}


def test_coerces_plain_json_schema_with_false_to_null() -> None:
    """Coerces false to null when schema type is null."""
    schema = {"type": "null"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, False)
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": None}


def test_coerces_union_schema_with_string_preferred() -> None:
    """For union type [number, string], string input stays as string."""
    schema = {"type": ["number", "string"]}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "1")
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": "1"}


def test_coerces_union_schema_with_boolean_number() -> None:
    """For union type [boolean, number], string '1' coerces to number 1."""
    schema = {"type": ["boolean", "number"]}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "1")
    result = validate_tool_arguments(tool, tool_call)
    assert result == {"value": 1}


def test_rejects_invalid_coercion_boolean_string_one() -> None:
    """Rejects '1' as invalid for boolean schema."""
    schema = {"type": "boolean"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "1")
    with pytest.raises(ValueError, match="Validation failed"):
        validate_tool_arguments(tool, tool_call)


def test_rejects_invalid_coercion_boolean_string_zero() -> None:
    """Rejects '0' as invalid for boolean schema."""
    schema = {"type": "boolean"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "0")
    with pytest.raises(ValueError, match="Validation failed"):
        validate_tool_arguments(tool, tool_call)


def test_rejects_invalid_coercion_null_string_null() -> None:
    """Rejects 'null' string as invalid for null schema."""
    schema = {"type": "null"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "null")
    with pytest.raises(ValueError, match="Validation failed"):
        validate_tool_arguments(tool, tool_call)


def test_rejects_invalid_coercion_integer_string_decimal() -> None:
    """Rejects '42.1' as invalid for integer schema."""
    schema = {"type": "integer"}
    tool, tool_call = _create_tool_call_with_plain_schema(schema, "42.1")
    with pytest.raises(ValueError, match="Validation failed"):
        validate_tool_arguments(tool, tool_call)
